{"command":"@'
Get-ChildItem -Path docs -Recurse -File | ForEach-Object {
  $hash = (Get-FileHash $_.FullName -Algorithm SHA256).Hash
  [PSCustomObject]@{ Hash = $hash; Length = $_.Length; Path = $_.FullName.Substring((Get-Location).Path.Length + 1) }
} | Sort-Object Hash, Path | Format-Table -AutoSize
'@ | powershell -NoProfile -Command -","workdir":"d:\demo1\openfons","timeout_ms":20000}

{"command":"@'
$files = Get-ChildItem -Path docs -Recurse -File
$groups = $files | Group-Object { (Get-FileHash $_.FullName -Algorithm SHA256).Hash } | Sort-Object Count -Descending
foreach ($g in $groups) {
  "COUNT=$($g.Count)"
  foreach ($f in $g.Group) { "  $($f.FullName.Substring((Get-Location).Path.Length + 1))" }
  ""
}
'@ | powershell -NoProfile -Command -","workdir":"d:\demo1\openfons","timeout_ms":20000}
